            ['nombre' => 'Cinta Adhesiva Scotch', 'cat' => 19, 'pv' => 3.5, 'pc' => 2.5, 'um' => 'UND', 'codigo' => 'M0223', 'barcode' => '7751000222'],
            ['nombre' => 'Globo de Cumpleanos x10', 'cat' => 19, 'pv' => 5.0, 'pc' => 3.6, 'um' => 'UND', 'codigo' => 'M0224', 'barcode' => '7751000223'],
            ['nombre' => 'Vaso Desechable x25', 'cat' => 19, 'pv' => 5.5, 'pc' => 4.0, 'um' => 'UND', 'codigo' => 'M0225', 'barcode' => '7751000224'],
            ['nombre' => 'Plato Desechable x10', 'cat' => 19, 'pv' => 6.0, 'pc' => 4.4, 'um' => 'UND', 'codigo' => 'M0226', 'barcode' => '7751000225'],
        ];

        foreach ($productos as $p) {
            $existente = Producto::where('empresa_id', $empresaId)
                ->where('codigo', $p['codigo'])->first();
            if ($existente) { continue; }

            Producto::create([
                'empresa_id'         => $empresaId,
                'categoria_id'       => $catIds[$p['cat']],
                'codigo'             => $p['codigo'],
                'codigo_barras'      => $p['barcode'],
                'descripcion'        => $p['nombre'],
                'tipo'               => 'producto',
                'unidad_medida'      => $p['um'],
                'precio_venta'       => $p['pv'],
                'precio_compra'      => $p['pc'],
                'afecto_igv'         => true,
                'afecto_isc'         => false,
                'afecto_icbper'      => false,
                'tipo_afectacion_igv'=> '10',
                'controla_stock'     => true,
                'stock_minimo'       => 5,
                'stock_actual'       => rand(15, 60),
                'requiere_receta'    => false,
                'activo'             => true,
            ]);
        }

        if (isset($this->command)) {
            $this->command->info('MinimarketBasicoSeeder: ' . count($productos) . ' productos cargados en empresa ' . $empresaId);
        }
    }
}
